// Select render mode via BuildOptions
let pdf = build_aipdf(&xml, &BuildOptions {
    title: "My Document".to_string(),
    render: RenderMode::Full,
    page: PageOptions::letter(),
    ..Default::default()
})?;

if trimmed.len() > 16 * 1024 * 1024 {
    return Err(AipdfError::InvalidXml(
        "semantic XML exceeds 16 MiB safety limit".to_string(),
    ));
}

use aipdf::{AipdfDocument, BuildOptions, RenderMode, PageOptions};

// Open and query
let doc = AipdfDocument::open("document.aipdf")?;
let xml    = doc.to_xml()?;
let md     = doc.to_markdown()?;
let onto   = doc.to_onto()?;
let blocks = doc.get_reading_order()?;
let tables = doc.get_tables()?;
let cites  = doc.find_citations()?;

import { open, buildFromSource } from 'aipdf';

